def yes_jwt
  @yes_jwt ||= TokenFactory.new(Scope.all).valid
end

def expired_jwt
  @expired_jwt ||= TokenFactory.new(Scope.all).expired
end

def yes_jwt_id
  Seeds.new.yes_jwt_id
end

def unsigned_jwt
  JwtHelper.jwt(:unsigned)
end

def forged_jwt
  JwtHelper.jwt(:forged)
end

def yes_jwt_user
  JwtTokenService.instance.extract_user(yes_jwt)
end

def expired_jwt_user
  JwtTokenService.instance.extract_user(expired_jwt)
end

def corrupted_jwt
  JwtHelper.jwt(:corrupted)
end

def nope_jwt
  JwtHelper.jwt(:no_scopes)
end
